// Parses THIRD-PARTY-NOTICES.txt (generated by generate-license-file)
// into a compact JSON array for the Help > Licenses UI.

const fs = require('fs');
const path = require('path');

const input = path.join(__dirname, '..', 'THIRD-PARTY-NOTICES.txt');
const output = path.join(__dirname, '..', 'src', 'renderer', 'data', 'oss-licenses.json');

if (!fs.existsSync(input)) {
  console.error('THIRD-PARTY-NOTICES.txt not found — run "npm run licenses" first');
  process.exit(1);
}

const raw = fs.readFileSync(input, 'utf-8');
const blocks = raw.split(/^-----------$/m).filter(b => b.trim());

const entries = [];
for (const block of blocks) {
  const pkgMatch = block.match(/^ - (.+)$/gm);
  if (!pkgMatch) continue;

  const packages = pkgMatch.map(l => {
    const m = l.match(/^ - (.+)@(\d.*)$/);
    return m ? { name: m[1], version: m[2] } : { name: l.replace(/^ - /, ''), version: '' };
  });

  // License text comes after "contain the following license:"
  const textMatch = block.split(/contains? the following license:\n/i);
  const licenseText = (textMatch[1] || '').trim();

  // Detect license type from first line of license text
  const firstLine = licenseText.split('\n')[0].trim();
  let licenseType = 'Unknown';
  if (/MIT/i.test(firstLine)) licenseType = 'MIT';
  else if (/Apache.*2/i.test(firstLine)) licenseType = 'Apache-2.0';
  else if (/BSD.*3/i.test(firstLine)) licenseType = 'BSD-3-Clause';
  else if (/BSD.*2/i.test(firstLine)) licenseType = 'BSD-2-Clause';
  else if (/ISC/i.test(firstLine)) licenseType = 'ISC';
  else if (/0BSD/i.test(firstLine)) licenseType = '0BSD';
  else if (firstLine.length < 40) licenseType = firstLine || 'Unknown';

  entries.push({ packages, licenseType, licenseText });
}

// Flatten for a summary view: one entry per package
const flat = [];
for (const e of entries) {
  for (const p of e.packages) {
    flat.push({ name: p.name, version: p.version, license: e.licenseType });
  }
}
flat.sort((a, b) => a.name.localeCompare(b.name));

fs.writeFileSync(output, JSON.stringify({ summary: flat, groups: entries }, null, 2));
console.log(`Parsed ${flat.length} packages in ${entries.length} license groups → ${output}`);
